package com.example.pool;

import javax.sql.DataSource;
import java.sql.Connection;
import java.sql.SQLException;
import java.util.concurrent.BlockingQueue;
import java.util.concurrent.LinkedBlockingQueue;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;

public class HikariPool implements DataSource {
    private final BlockingQueue<PooledConnection> availableConnections;
    private final ConnectionFactory connectionFactory;
    private final int maxSize;
    private final int minIdle;
    private final long maxLifetimeMs;
    private final long idleTimeoutMs;
    private final AtomicInteger activeCount = new AtomicInteger(0);
    private volatile boolean isShutdown = false;

    public HikariPool(ConnectionFactory factory, int poolSize, int minIdle,
                      long maxLifetimeMs, long idleTimeoutMs) {
        this.connectionFactory = factory;
        this.maxSize = poolSize;
        this.minIdle = minIdle;
        this.maxLifetimeMs = maxLifetimeMs;
        this.idleTimeoutMs = idleTimeoutMs;
        this.availableConnections = new LinkedBlockingQueue<>(poolSize);

        // Initialize minimum idle connections
        for (int i = 0; i < minIdle; i++) {
            try {
                availableConnections.put(createNewConnection());
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }
    }

    @Override
    public Connection getConnection() throws SQLException {
        if (isShutdown) throw new SQLException("Pool is shut down");

        PooledConnection conn = availableConnections.poll();
        if (conn != null && !conn.isExpired()) {
            return conn;
        }

        if (activeCount.get() < maxSize) {
            try {
                return createNewConnection();
            } catch (SQLException e) {
                throw new SQLException("Failed to create new connection", e);
            }
        }

        // Wait for a connection to be returned
        try {
            conn = availableConnections.poll(30, TimeUnit.SECONDS);
            if (conn == null || conn.isExpired()) {
                throw new SQLException("Connection acquisition timeout");
            }
            return conn;
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            throw new SQLException("Interrupted while waiting for connection");
        }
    }

    public void releaseConnection(PooledConnection conn) {
        activeCount.decrementAndGet();
        if (!isShutdown && !conn.isExpired()) {
            availableConnections.offer(conn);
        }
    }

    private PooledConnection createNewConnection() throws SQLException {
        activeCount.incrementAndGet();
        Connection physicalConn = connectionFactory.create();
        return new PooledConnection(physicalConn, maxLifetimeMs);
    }

    public int getActiveConnections() { return activeCount.get(); }
    public int getIdleConnections() { return availableConnections.size(); }

    public void shutdown() {
        isShutdown = true;
        availableConnections.forEach(PooledConnection::close);
        availableConnections.clear();
    }
}

package com.example.ratelimit;

import com.google.common.util.concurrent.RateLimiter;
import org.aspectj.lang.ProceedingJoinPoint;
import org.aspectj.lang.annotation.Around;
import org.aspectj.lang.annotation.Aspect;
import org.springframework.stereotype.Component;

import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@Aspect
@Component
public class RateLimitAspect {
    private final Map<String, RateLimiter> limiters = new ConcurrentHashMap<>();

    @Around("@annotation(com.example.ratelimit.RateLimit)")
    public Object rateLimit(ProceedingJoinPoint joinPoint) throws Throwable {
        String key = generateKey(joinPoint);
        RateLimiter limiter = limiters.computeIfAbsent(key, k -> {
            RateLimit annotation = getAnnotation(joinPoint);
            return RateLimiter.create(annotation.permitsPerSecond());
        });

        if (!limiter.tryAcquire(annotation.timeoutSeconds(), java.util.concurrent.TimeUnit.SECONDS)) {
            throw new RateLimitExceededException(
                "Rate limit exceeded for: " + key + 
                " (" + annotation.permitsPerSecond() + " permits/second)"
            );
        }

        return joinPoint.proceed();
    }

    private String generateKey(ProceedingJoinPoint joinPoint) {
        String className = joinPoint.getTarget().getClass().getSimpleName();
        String methodName = joinPoint.getSignature().getName();
        return className + "." + methodName;
    }

    private RateLimit getAnnotation(ProceedingJoinPoint joinPoint) {
        return joinPoint.getMethod().getAnnotation(RateLimit.class);
    }
}

import java.lang.annotation.ElementType;
import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;
import java.lang.annotation.Target;

@Target(ElementType.METHOD)
@Retention(RetentionPolicy.RUNTIME)
public @interface RateLimit {
    double permitsPerSecond() default 10.0;
    int timeoutSeconds() default 1;
}

