package com.example.health;

import org.springframework.boot.actuate.health.CompositeHealthContributor;
import org.springframework.boot.actuate.health.Health;
import org.springframework.boot.actuate.health.HealthIndicator;
import org.springframework.boot.actuate.health.NamedContributor;
import org.springframework.stereotype.Component;

import java.util.HashMap;
import java.util.Map;

@Component
public class DatabaseHealthIndicator implements HealthIndicator {
    private final DataSource dataSource;
    private final Logger logger = LoggerFactory.getLogger(DatabaseHealthIndicator.class);

    public DatabaseHealthIndicator(DataSource dataSource) {
        this.dataSource = dataSource;
    }

    @Override
    public Health health() {
        try {
            long startTime = System.currentTimeMillis();
            try (var conn = dataSource.getConnection();
                 var stmt = conn.createStatement();
                 var rs = stmt.executeQuery("SELECT 1")) {

                if (rs.next()) {
                    long duration = System.currentTimeMillis() - startTime;
                    return Health.up()
                        .withDetail("responseTime", duration + "ms")
                        .withDetail("database", conn.getMetaData().getDatabaseProductName())
                        .build();
                }
            }
        } catch (Exception e) {
            logger.error("Database health check failed", e);
            return Health.down()
                .withException(e)
                .withDetail("error", e.getMessage())
                .build();
        }
        return Health.unknown().build();
    }
}

@Component
public class RedisHealthIndicator implements HealthIndicator {
    private final RedisTemplate<String, Object> redisTemplate;

    public RedisHealthIndicator(RedisTemplate<String, Object> redisTemplate) {
        this.redisTemplate = redisTemplate;
    }

    @Override
    public Health health() {
        try {
            Boolean ping = redisTemplate.getConnectionFactory()
                .getConnection().ping();

            if (Boolean.TRUE.equals(ping)) {
                return Health.up().build();
            } else {
                return Health.down().build();
            }
        } catch (Exception e) {
            return Health.down().withException(e).build();
        }
    }
}

@Component
public class CompositeHealthContributorImpl implements CompositeHealthContributor {
    private final Map<String, HealthIndicator> indicators = new HashMap<>();

    public CompositeHealthContributorImpl(List<HealthIndicator> indicatorList) {
        indicatorList.forEach(indicator -> 
            indicators.put(indicator.getClass().getSimpleName(), indicator)
        );
    }

    @Override
    public HealthIndicator getIndicator(String name) {
        return indicators.get(name);
    }

    @Override
    public Iterator<NamedContributor<HealthIndicator>> iterator() {
        return indicators.entrySet().stream()
            .map(e -> NamedContributor.of(e.getKey(), e.getValue()))
            .iterator();
    }
}

package com.example.retry;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.retry.backoff.ExponentialBackOffPolicy;
import org.springframework.retry.interceptor.SimpleRetryPolicy;
import org.springframework.retry.policy.RetryPolicy;
import org.springframework.retry.support.RetryTemplate;

import java.util.Collections;

@Configuration
public class RetryConfig {

    @Bean
    public RetryTemplate retryTemplate() {
        RetryTemplate template = new RetryTemplate();

        // Configure retry policy
        SimpleRetryPolicy retryPolicy = new SimpleRetryPolicy();
        retryPolicy.setMaxAttempts(3);
        template.setRetryPolicy(retryPolicy);

        // Configure back-off policy
        ExponentialBackOffPolicy backOffPolicy = new ExponentialBackOffPolicy();
        backOffPolicy.setInitialInterval(1000);
        backOffPolicy.setMultiplier(2.0);
        backOffPolicy.setMaxInterval(30000);
        template.setBackOffPolicy(backOffPolicy);

        return template;
    }

    @Bean
    public RetryTemplate httpRetryTemplate() {
        RetryTemplate template = new RetryTemplate();

        // Only retry on specific exceptions
        Map<Class<? extends Throwable>, Boolean> retryableExceptions = 
            Collections.singletonMap(java.net.ConnectException.class, true);
        template.setRetryPolicy(new SimpleRetryPolicy(5, retryableExceptions));

        // Fixed back-off
        FixedBackOffPolicy backOff = new FixedBackOffPolicy();
        backOff.setBackOffPeriod(2000);
        template.setBackOffPolicy(backOff);

        return template;
    }
}

@Service
public class ResilientHttpClient {
    private final RetryTemplate retryTemplate;
    private final RestTemplate restTemplate;

    public ResilientHttpClient(RetryTemplate retryTemplate, RestTemplate restTemplate) {
        this.retryTemplate = retryTemplate;
        this.restTemplate = restTemplate;
    }

    public ResponseEntity<String> fetchWithRetry(String url) {
        return retryTemplate.execute(context -> {
            System.out.println("Attempt: " + context.getRetryCount());
            return restTemplate.getForEntity(url, String.class);
        },
        (retryContext, exception) -> {
            System.err.println("Retry failed after attempts: " + retryContext.getRetryCount());
        });
    }

    public User getUserWithRetry(String userId) {
        return retryTemplate.execute(context -> {
            ResponseEntity<UserResponse> response = restTemplate.exchange(
                "/api/users/" + userId, HttpMethod.GET, null, UserResponse.class);
            return UserMapper.toDomain(response.getBody());
        });
    }
}

