package com.example.circuitbreaker;

import io.github.resilience4j.circuitbreaker.CircuitBreaker;
import io.github.resilience4j.circuitbreaker.CircuitBreakerConfig;
import io.github.resilience4j.circuitbreaker.CircuitBreakerRegistry;
import io.github.resilience4j.timelimiter.TimeLimiter;
import io.github.resilience4j.timelimiter.TimeLimiterConfig;
import io.github.resilience4j.timelimiter.TimeLimiterRegistry;

import java.time.Duration;
import java.util.concurrent.CompletableFuture;
import java.util.function.Supplier;

public class CircuitBreakerService {
    private final CircuitBreakerRegistry circuitBreakerRegistry;
    private final TimeLimiterRegistry timeLimiterRegistry;

    public CircuitBreakerService() {
        CircuitBreakerConfig config = CircuitBreakerConfig.custom()
            .failureRateThreshold(50)
            .waitDurationInOpenState(Duration.ofSeconds(30))
            .slidingWindowSize(10)
            .minimumNumberOfCalls(5)
            .permittedNumberOfCallsInHalfOpenState(3)
            .automaticTransitionFromOpenToHalfOpenEnabled(true)
            .recordExceptions(
                java.net.SocketTimeoutException.class,
                java.net.ConnectException.class
            )
            .ignoreExceptions(
                IllegalArgumentException.class
            )
            .build();

        this.circuitBreakerRegistry = CircuitBreakerRegistry.of(config);

        TimeLimiterConfig tlConfig = TimeLimiterConfig.custom()
            .timeoutDuration(Duration.ofSeconds(5))
            .cancelRunningFuture(true)
            .build();
        this.timeLimiterRegistry = TimeLimiterRegistry.of(tlConfig);
    }

    public <T> CompletableFuture<T> executeWithCircuitBreaker(
            String serviceName, Supplier<CompletableFuture<T>> supplier) {

        CircuitBreaker circuitBreaker = circuitBreakerRegistry.circuitBreaker(serviceName);
        TimeLimiter timeLimiter = timeLimiterRegistry.timeLimiter(serviceName);

        Supplier<CompletableFuture<T>> decoratedSupplier = 
            CircuitBreaker.decorateFutureSupplier(circuitBreaker, supplier);
        decoratedSupplier = TimeLimiter.decorateFutureSupplier(timeLimiter, decoratedSupplier);

        return decoratedSupplier.get().exceptionally(ex -> {
            if (ex.getCause() instanceof io.github.resilience4j.circuitbreaker.CallNotPermittedException) {
                throw new ServiceUnavailableException(serviceName + " is circuit open");
            }
            throw new RuntimeException(ex);
        });
    }

    public void reportMetrics(String serviceName, CircuitBreaker.Metrics metrics) {
        System.out.printf("Service: %s | State: %s | Failure Rate: %.1f%% | Call Count: %d%n",
            serviceName,
            metrics.getState(),
            metrics.getFailureRate(),
            metrics.getNumberOfBufferedCalls()
        );
    }
}

package com.example.metrics;

import io.micrometer.core.instrument.Counter;
import io.micrometer.core.instrument.DistributionSummary;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Timer;
import org.springframework.stereotype.Service;

import java.time.Duration;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.TimeUnit;

@Service
public class MetricsService {
    private final MeterRegistry meterRegistry;
    private final Timer httpRequestTimer;
    private final Counter httpErrorsCounter;
    private final DistributionSummary requestSizeSummary;

    public MetricsService(MeterRegistry meterRegistry) {
        this.meterRegistry = meterRegistry;

        this.httpRequestTimer = Timer.builder("http.request.duration")
            .description("HTTP request duration")
            .tags("service", "user-service")
            .register(meterRegistry);

        this.httpErrorsCounter = Counter.builder("http.errors.total")
            .description("Total HTTP errors")
            .tags("service", "user-service")
            .register(meterRegistry);

        this.requestSizeSummary = DistributionSummary.builder("http.request.size.bytes")
            .description("HTTP request body size")
            .baseUnit("bytes")
            .register(meterRegistry);
    }

    public <T> T timedOperation(String operationName, java.util.function.Supplier<T> supplier) {
        return httpRequestTimer.record(supplier);
    }

    public void recordError() {
        httpErrorsCounter.increment();
    }

    public void recordRequestSize(long sizeBytes) {
        requestSizeSummary.record(sizeBytes);
    }

    public void recordBusinessMetric(String metricName, double value) {
        io.micrometer.core.instrument.Gauge.builder("business." + metricName, 
            this, obj -> getMetricValue(metricName))
            .tag("name", metricName)
            .register(meterRegistry);
    }

    private double getMetricValue(String name) {
